"""
VWAP Flow v4 — Kiyotaka Data Integration
Fetch OI, Funding Rate, Liquidation dari Kiyotaka API
untuk confirmation layer (filter fake breakouts).

Weight budget: ~30/hari (cached, smart rotation)
"""
import os
import time
import hmac
import hashlib
import json

try:
    import requests
except ImportError:
    requests = None

# ===== CONFIG =====
KIYOTAKA_API_KEY = os.environ.get('KIYOTAKA_API_KEY', '')
KIYOTAKA_BASE_URL = 'https://api.kiyotaka.ai'
KIYOTAKA_EXCHANGE = 'BINANCE_FUTURES'

# Weight limits
WEIGHT_PER_MIN = 10
WEIGHT_PER_DAY = 1000

# Cache settings (OI/Funding gak berubah tiap detik)
OI_CACHE_TTL = 300         # 5 menit
FUNDING_CACHE_TTL = 3600   # 1 jam (update tiap 8 jam)
LIQ_CACHE_TTL = 600        # 10 menit

# Confirmation thresholds
OI_RISE_THRESHOLD = 0.02       # OI naik > 2% = genuine breakout
OI_DROP_THRESHOLD = -0.02      # OI turun > 2% = fake breakout
FUNDING_EXTREME_LONG = 0.05    # Funding > 0.05% = overcrowded LONG
FUNDING_EXTREME_SHORT = -0.05  # Funding < -0.05% = overcrowded SHORT
LIQ_PROXIMITY_ATR = 2.0        # Liquidation cluster dalam 2x ATR = skip


class KiyotakaData:
    """Cache + fetch Kiyotaka market data."""

    def __init__(self, api_key=None):
        self.api_key = api_key or KIYOTAKA_API_KEY
        self._cache = {}  # key -> {'data': ..., 'time': ...}
        self._weight_used = 0
        self._weight_reset_time = time.time()

        if not self.api_key:
            print("[KIYOTAKA] ⚠️ No API key — confirmation layer disabled")

    @property
    def enabled(self):
        return bool(self.api_key) and requests is not None

    def _get_cache(self, key, ttl):
        """Ambil dari cache kalau masih fresh."""
        if key in self._cache:
            entry = self._cache[key]
            if time.time() - entry['time'] < ttl:
                return entry['data']
        return None

    def _set_cache(self, key, data):
        """Simpan ke cache."""
        self._cache[key] = {'data': data, 'time': time.time()}

    def _track_weight(self, weight=1):
        """Track weight usage."""
        now = time.time()
        # Reset setiap menit
        if now - self._weight_reset_time > 60:
            self._weight_used = 0
            self._weight_reset_time = now
        self._weight_used += weight

    def _request(self, endpoint, params):
        """Make API request ke Kiyotaka."""
        if not self.enabled:
            return None

        try:
            headers = {
                'X-Kiyotaka-Key': self.api_key,
                'Accept': 'application/json',
            }
            resp = requests.get(
                f"{KIYOTAKA_BASE_URL}{endpoint}",
                params=params,
                headers=headers,
                timeout=10,
            )
            if resp.status_code == 200:
                self._track_weight(params.get('weight', 1))
                return resp.json()
            else:
                print(f"[KIYOTAKA] HTTP {resp.status_code}: {resp.text[:100]}")
                return None
        except Exception as e:
            print(f"[KIYOTAKA] Request error: {e}")
            return None

    # ===== OI (Open Interest) =====
    def get_oi(self, symbol, period_sec=3600):
        """
        Fetch OI data. Returns: {'current': float, 'change_pct': float, 'trend': str}
        """
        cache_key = f"oi_{symbol}"
        cached = self._get_cache(cache_key, OI_CACHE_TTL)
        if cached is not None:
            return cached

        now = int(time.time())
        params = {
            'type': 'OPEN_INTEREST_AGG',
            'exchange': KIYOTAKA_EXCHANGE,
            'rawSymbol': symbol,
            'interval': '1m',
            'from': now - period_sec,
            'period': period_sec,
        }

        data = self._request('/v1/points', params)
        if not data or 'series' not in data:
            return None

        try:
            series = data['series'][0]['points']
            if len(series) < 2:
                return None

            current_oi = float(series[-1].get('oi', 0))
            prev_oi = float(series[-max(2, len(series)//4)].get('oi', 0))  # ~25% back
